#[derive(Serialize)]
struct MyStruct {
    #[serde(getter = "get_value_with_prefix", skip_serializing_if = "String::is_empty")]
    value: String,
}
impl MyStruct { fn get_value_with_prefix(&self) -> String { format!("prefix-{}", self.value) } }
